import { useState, useEffect, useCallback, useRef, MutableRefObject } from 'react'
import type { ClientToCanvasPercent } from './types.js'

interface UsePanningResult {
  panX: number
  isPanning: boolean
  handlePanStart: (e: React.MouseEvent) => void
  clientToCanvasPercent: ClientToCanvasPercent
  clientToCanvasPercentRef: MutableRefObject<ClientToCanvasPercent>
}

const DRAG_THRESHOLD = 3 // px of movement before we consider it a drag, not a click

export function usePanning(
  containerRef: MutableRefObject<HTMLDivElement | null>,
  canvasWidth: number,
  viewportWidth: number,
  viewportHeight: number
): UsePanningResult {
  const [panX, setPanX] = useState(0)
  const [isPanning, setIsPanning] = useState(false)
  const panXRef = useRef(panX)
  panXRef.current = panX

  const maxPan = Math.max(0, canvasWidth - viewportWidth)
  const maxPanRef = useRef(maxPan)
  maxPanRef.current = maxPan

  // Clamp panX when bounds change (e.g. tiles removed)
  useEffect(() => {
    if (panX > maxPan) {
      setPanX(maxPan)
    }
  }, [panX, maxPan])

  const clientToCanvasPercent: ClientToCanvasPercent = useCallback((clientX: number, clientY: number) => {
    const container = containerRef.current
    if (!container || viewportWidth === 0 || viewportHeight === 0) {
      return { x: 0, y: 0 }
    }
    const rect = container.getBoundingClientRect()
    const x = (clientX - rect.left + panXRef.current) / viewportWidth * 100
    const y = (clientY - rect.top) / viewportHeight * 100
    return { x, y }
  }, [containerRef, viewportWidth, viewportHeight])

  const clientToCanvasPercentRef = useRef(clientToCanvasPercent)
  clientToCanvasPercentRef.current = clientToCanvasPercent

  const handlePanStart = useCallback((e: React.MouseEvent) => {
    // Middle mouse button only
    if (e.button !== 1) return

    const startX = e.clientX
    const startY = e.clientY
    const startPanX = panXRef.current
    let dragging = false
    let rafId: number | null = null

    const handleMove = (moveE: MouseEvent) => {
      const dx = Math.abs(moveE.clientX - startX)
      const dy = Math.abs(moveE.clientY - startY)

      // Start panning once movement exceeds threshold
      if (!dragging && (dx > DRAG_THRESHOLD || dy > DRAG_THRESHOLD)) {
        dragging = true
        setIsPanning(true)
      }

      if (!dragging) return

      if (rafId !== null) return
      rafId = requestAnimationFrame(() => {
        rafId = null
        const panDx = startX - moveE.clientX
        const newPanX = Math.max(0, Math.min(maxPanRef.current, startPanX + panDx))
        setPanX(newPanX)
      })
    }

    // Suppress middle-click paste when we're dragging (not clicking)
    const suppressPaste = (pasteE: MouseEvent) => {
      if (dragging && pasteE.button === 1) {
        pasteE.preventDefault()
        pasteE.stopPropagation()
      }
    }

    const handleUp = (upE: MouseEvent) => {
      if (rafId !== null) cancelAnimationFrame(rafId)

      if (dragging) {
        // We were panning — suppress paste and clean up
        setIsPanning(false)
        upE.preventDefault()
        upE.stopPropagation()
        // Trigger terminal refit after panning
        window.dispatchEvent(new Event('resize'))
      }
      // If not dragging, do nothing — let xterm handle paste naturally

      window.removeEventListener('mousemove', handleMove)
      window.removeEventListener('mouseup', handleUp, true)
      // Defer removal: auxclick fires AFTER mouseup in the same cycle,
      // so the suppressPaste listener must survive until then
      setTimeout(() => {
        window.removeEventListener('click', suppressPaste, true)
        window.removeEventListener('auxclick', suppressPaste, true)
      }, 0)
    }

    window.addEventListener('mousemove', handleMove)
    window.addEventListener('mouseup', handleUp, true)      // capture phase
    window.addEventListener('click', suppressPaste, true)    // capture phase
    window.addEventListener('auxclick', suppressPaste, true) // capture phase — middle-click fires auxclick
  }, [])

  return {
    panX,
    isPanning,
    handlePanStart,
    clientToCanvasPercent,
    clientToCanvasPercentRef
  }
}

import { useCallback, MutableRefObject } from 'react'
import type { TileLayout, DropZone } from '../tiled-layout-utils.js'
import {
  computeDropZone,
  validateLayout,
  removeTilePreservingStructure,
  splitTile,
  addTabToExistingTile
} from '../tiled-layout-utils.js'
import type { OpenTab, ClientToCanvasPercent } from './types.js'

interface DragDropState {
  draggedTile: string | null
  draggedSidebarProject: string | null
  dropTarget: string | null
  currentDropZone: DropZone | null
}

interface DragDropActions {
  setDraggedTile: (id: string | null) => void
  setDraggedSidebarProject: (id: string | null) => void
  setDropTarget: (id: string | null) => void
  setCurrentDropZone: (zone: DropZone | null) => void
}

export function useHandleDragStart(
  setDraggedTile: (id: string | null) => void
): (e: React.DragEvent, tileId: string) => void {
  return useCallback((e: React.DragEvent, tileId: string) => {
    e.dataTransfer.setData('text/plain', tileId)
    e.dataTransfer.effectAllowed = 'move'
    setDraggedTile(tileId)
  }, [setDraggedTile])
}

export function useHandleContainerDragOver(
  containerRef: MutableRefObject<HTMLDivElement | null>,
  effectiveLayout: TileLayout[],
  state: Pick<DragDropState, 'draggedTile' | 'draggedSidebarProject'>,
  actions: Pick<DragDropActions, 'setDraggedSidebarProject' | 'setDropTarget' | 'setCurrentDropZone'>,
  clientToCanvasPercentRef?: MutableRefObject<ClientToCanvasPercent>
): (e: React.DragEvent) => void {
  const { draggedTile, draggedSidebarProject } = state
  const { setDraggedSidebarProject, setDropTarget, setCurrentDropZone } = actions

  return useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.dataTransfer.dropEffect = 'move'

    if (!containerRef.current) return

    const isSidebarProjectDrag = e.dataTransfer.types.includes('application/x-sidebar-project')

    if (isSidebarProjectDrag) {
      if (!draggedSidebarProject) {
        setDraggedSidebarProject('pending')
      }

      const { x: mouseX, y: mouseY } = clientToCanvasPercentRef?.current
        ? clientToCanvasPercentRef.current(e.clientX, e.clientY)
        : (() => { const rect = containerRef.current!.getBoundingClientRect(); return { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 } })()

      const zone = computeDropZone(effectiveLayout, null, mouseX, mouseY)
      setCurrentDropZone(zone)
      setDropTarget(zone?.targetTileId || null)
      return
    }

    if (!draggedTile) return

    const { x: mouseX, y: mouseY } = clientToCanvasPercentRef?.current
      ? clientToCanvasPercentRef.current(e.clientX, e.clientY)
      : (() => { const rect = containerRef.current!.getBoundingClientRect(); return { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 } })()

    const zone = computeDropZone(effectiveLayout, draggedTile, mouseX, mouseY)
    setCurrentDropZone(zone)
    setDropTarget(zone?.targetTileId || null)
  }, [containerRef, draggedTile, draggedSidebarProject, effectiveLayout, setDraggedSidebarProject, setDropTarget, setCurrentDropZone, clientToCanvasPercentRef])
}

export function useHandleContainerDragLeave(
  containerRef: MutableRefObject<HTMLDivElement | null>,
  actions: Pick<DragDropActions, 'setDraggedSidebarProject' | 'setDropTarget' | 'setCurrentDropZone'>
): (e: React.DragEvent) => void {
  const { setDraggedSidebarProject, setDropTarget, setCurrentDropZone } = actions

  return useCallback((e: React.DragEvent) => {
    const rect = containerRef.current?.getBoundingClientRect()
    if (rect) {
      const { clientX, clientY } = e
      if (clientX < rect.left || clientX > rect.right || clientY < rect.top || clientY > rect.bottom) {
        setCurrentDropZone(null)
        setDropTarget(null)
        setDraggedSidebarProject(null)
      }
    }
  }, [containerRef, setDraggedSidebarProject, setDropTarget, setCurrentDropZone])
}

export function useApplyDropZone(
  tabs: OpenTab[],
  containerSizeRef: MutableRefObject<{ width: number; height: number }>
): (layout: TileLayout[], draggedId: string, zone: DropZone) => TileLayout[] {
  return useCallback((layout: TileLayout[], draggedId: string, zone: DropZone): TileLayout[] => {
    const { width, height } = containerSizeRef.current

    if (zone.type === 'swap') {
      const sourceTile = layout.find(t => t.id === draggedId)
      const targetTile = layout.find(t => t.id === zone.targetTileId)

      if (sourceTile && targetTile) {
        // Check if source and target share a project → merge tabs
        const sourceProject = sourceTile.tabIds
          .map(id => tabs.find(t => t.id === id)?.projectPath)
          .find(p => p != null)
        const targetProject = targetTile.tabIds
          .map(id => tabs.find(t => t.id === id)?.projectPath)
          .find(p => p != null)

        if (sourceProject && sourceProject === targetProject) {
          // Merge: add source tabs into target tile, then remove source tile
          let merged = layout
          for (const tabId of sourceTile.tabIds) {
            merged = addTabToExistingTile(merged, targetTile.id, tabId)
          }
          return removeTilePreservingStructure(merged, draggedId, tabs, width, height)
        }

        // Different projects → swap positions
        return layout.map(tile => {
          if (tile.id === draggedId) {
            return { ...tile, x: targetTile.x, y: targetTile.y, width: targetTile.width, height: targetTile.height }
          }
          if (tile.id === zone.targetTileId) {
            return { ...tile, x: sourceTile.x, y: sourceTile.y, width: sourceTile.width, height: sourceTile.height }
          }
          return tile
        })
      }
      return layout
    }

    const direction = zone.type.replace('split-', '') as 'top' | 'bottom' | 'left' | 'right'
    // For drag operations, just remove the tile without expanding neighbors.
    // The tile is being moved, not deleted — expansion would distort the layout.
    const withoutDragged = layout.filter(t => t.id !== draggedId)
    return splitTile(withoutDragged, zone.targetTileId, draggedId, direction)
  }, [tabs, containerSizeRef])
}

import { useEffect, useCallback, MutableRefObject } from 'react'
import type { TileLayout } from '../tiled-layout-utils.js'
import { findContiguousTilesOnDivider, findOverlappingTilesOnDivider, MIN_SIZE } from '../tiled-layout-utils.js'
import type { TileResizeState, ResizeEdge, ClientToCanvasPercent } from './types.js'

function getCursorForEdge(edge: string): string {
  switch (edge) {
    case 'right':
    case 'left':
      return 'ew-resize'
    case 'top':
    case 'bottom':
      return 'ns-resize'
    case 'top-left':
    case 'bottom-right':
      return 'nwse-resize'
    case 'top-right':
    case 'bottom-left':
      return 'nesw-resize'
    default:
      return 'default'
  }
}

export function useStartTileResize(
  effectiveLayout: TileLayout[],
  setTileResizing: (state: TileResizeState | null) => void,
  setHoveredEdge: (state: { tileId: string; edge: string } | null) => void
): (e: React.MouseEvent, tileId: string, edge: ResizeEdge) => void {
  return useCallback((e: React.MouseEvent, tileId: string, edge: ResizeEdge) => {
    e.preventDefault()
    e.stopPropagation()
    setHoveredEdge(null)
    const tile = effectiveLayout.find(t => t.id === tileId)
    if (tile) {
      const rightDivider = tile.x + tile.width
      const leftDivider = tile.x
      const bottomDivider = tile.y + tile.height
      const topDivider = tile.y

      // Find contiguous tile groups on each divider (only tiles connected to this tile)
      // then find overlapping tiles on the opposite side of each divider
      const tilesLeftOfRight = findContiguousTilesOnDivider(rightDivider, true, 'before', effectiveLayout, tile)
      const tilesRightOfRight = findOverlappingTilesOnDivider(rightDivider, true, 'after', effectiveLayout, tilesLeftOfRight)
      const tilesRightOfLeft = findContiguousTilesOnDivider(leftDivider, true, 'after', effectiveLayout, tile)
      const tilesLeftOfLeft = findOverlappingTilesOnDivider(leftDivider, true, 'before', effectiveLayout, tilesRightOfLeft)
      const tilesAboveBottom = findContiguousTilesOnDivider(bottomDivider, false, 'before', effectiveLayout, tile)
      const tilesBelowBottom = findOverlappingTilesOnDivider(bottomDivider, false, 'after', effectiveLayout, tilesAboveBottom)
      const tilesBelowTop = findContiguousTilesOnDivider(topDivider, false, 'after', effectiveLayout, tile)
      const tilesAboveTop = findOverlappingTilesOnDivider(topDivider, false, 'before', effectiveLayout, tilesBelowTop)

      setTileResizing({
        tileId,
        edge,
        startX: e.clientX,
        startY: e.clientY,
        startLayout: { ...tile },
        tilesLeftOfRightDivider: tilesLeftOfRight,
        tilesRightOfRightDivider: tilesRightOfRight,
        tilesLeftOfLeftDivider: tilesLeftOfLeft,
        tilesRightOfLeftDivider: tilesRightOfLeft,
        tilesAboveBottomDivider: tilesAboveBottom,
        tilesBelowBottomDivider: tilesBelowBottom,
        tilesAboveTopDivider: tilesAboveTop,
        tilesBelowTopDivider: tilesBelowTop,
        rightDividerPos: rightDivider,
        leftDividerPos: leftDivider,
        bottomDividerPos: bottomDivider,
        topDividerPos: topDivider
      })
    }
  }, [effectiveLayout, setTileResizing, setHoveredEdge])
}

export function useTileResizeEffect(
  tileResizing: TileResizeState | null,
  containerRef: MutableRefObject<HTMLDivElement | null>,
  effectiveLayoutRef: MutableRefObject<TileLayout[]>,
  onLayoutChangeRef: MutableRefObject<(layout: TileLayout[]) => void>,
  setTileResizing: (state: TileResizeState | null) => void,
  clientToCanvasPercentRef?: MutableRefObject<ClientToCanvasPercent>
): void {
  useEffect(() => {
    if (!tileResizing || !containerRef.current) return

    let rafId: number | null = null
    const handleTileResizeMove = (e: MouseEvent) => {
      if (!containerRef.current) return
      if (rafId !== null) return
      rafId = requestAnimationFrame(() => {
        rafId = null
        if (!containerRef.current) return
        const rect = containerRef.current.getBoundingClientRect()
        const {
          edge,
          tilesLeftOfRightDivider, tilesRightOfRightDivider,
          tilesLeftOfLeftDivider, tilesRightOfLeftDivider,
          tilesAboveBottomDivider, tilesBelowBottomDivider,
          tilesAboveTopDivider, tilesBelowTopDivider,
          rightDividerPos, leftDividerPos, bottomDividerPos, topDividerPos
        } = tileResizing
        const currentLayout = effectiveLayoutRef.current

        const canvasCoords = clientToCanvasPercentRef?.current
          ? clientToCanvasPercentRef.current(e.clientX, e.clientY)
          : { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 }
        const mouseXPercent = canvasCoords.x
        const mouseYPercent = canvasCoords.y

        const tileUpdates = new Map<string, TileLayout>()

        const moveVerticalDivider = (originalPos: number, tilesLeft: TileLayout[], tilesRight: TileLayout[]) => {
          if (tilesLeft.length === 0 && tilesRight.length === 0) return
          // Block left outer boundary (x=0) but allow free resize otherwise
          if (tilesLeft.length === 0 && originalPos < 1) return
          let minPos = 0
          let maxPos = Infinity
          tilesLeft.forEach(tile => { minPos = Math.max(minPos, tile.x + MIN_SIZE) })
          tilesRight.forEach(tile => { maxPos = Math.min(maxPos, tile.x + tile.width - MIN_SIZE) })
          const newPos = Math.max(minPos, Math.min(maxPos, mouseXPercent))

          tilesLeft.forEach(tile => {
            const currentTile = currentLayout.find(t => t.id === tile.id) || tile
            const existing = tileUpdates.get(tile.id) || { ...currentTile }
            existing.width = newPos - tile.x
            tileUpdates.set(tile.id, existing)
          })
          tilesRight.forEach(tile => {
            const currentTile = currentLayout.find(t => t.id === tile.id) || tile
            const existing = tileUpdates.get(tile.id) || { ...currentTile }
            const originalRight = tile.x + tile.width
            existing.x = newPos
            existing.width = originalRight - newPos
            tileUpdates.set(tile.id, existing)
          })
        }

        const moveHorizontalDivider = (originalPos: number, tilesAbove: TileLayout[], tilesBelow: TileLayout[]) => {
          if (tilesAbove.length === 0 && tilesBelow.length === 0) return
          let minPos = 0
          let maxPos = 100
          tilesAbove.forEach(tile => { minPos = Math.max(minPos, tile.y + MIN_SIZE) })
          tilesBelow.forEach(tile => { maxPos = Math.min(maxPos, tile.y + tile.height - MIN_SIZE) })
          const newPos = Math.max(minPos, Math.min(maxPos, mouseYPercent))

          tilesAbove.forEach(tile => {
            const currentTile = currentLayout.find(t => t.id === tile.id) || tile
            const existing = tileUpdates.get(tile.id) || { ...currentTile }
            existing.height = newPos - tile.y
            tileUpdates.set(tile.id, existing)

import { useMemo, useEffect, useRef, MutableRefObject } from 'react'
import type { TileLayout } from '../tiled-layout-utils.js'
import {
  generateDefaultLayout,
  validateLayout,
  addTileToLayout,
  removeTabFromTile,
  getAllTabIdsFromLayout,
  migrateTile
} from '../tiled-layout-utils.js'
import type { OpenTab } from './types.js'

export function useEffectiveLayout(
  layout: TileLayout[],
  tabs: OpenTab[],
  containerSizeRef: MutableRefObject<{ width: number; height: number }>,
  onLayoutChange: (layout: TileLayout[]) => void
): {
  effectiveLayout: TileLayout[]
  effectiveLayoutRef: MutableRefObject<TileLayout[]>
  activeTabIdRef: MutableRefObject<string | null>
} {
  const effectiveLayoutRef = useRef<TileLayout[]>([])
  const activeTabIdRef = useRef<string | null>(tabs.length > 0 ? tabs[tabs.length - 1].id : null)

  const effectiveLayout = useMemo(() => {
    const { width, height } = containerSizeRef.current

    if (layout.length === 0) {
      return generateDefaultLayout(tabs, width, height)
    }

    // Ensure all tiles are migrated to the new format
    const migratedLayout = layout.map(migrateTile)

    const layoutTabIds = getAllTabIdsFromLayout(migratedLayout)
    const tabIds = new Set(tabs.map(t => t.id))
    const addedTabs = tabs.filter(t => !layoutTabIds.has(t.id))
    const removedTabIds = [...layoutTabIds].filter(id => !tabIds.has(id))

    if (addedTabs.length === 0 && removedTabIds.length === 0) {
      return validateLayout(migratedLayout, tabs, width, height)
    }

    let newLayout = [...migratedLayout]

    // Remove tabs that no longer exist
    for (const removedId of removedTabIds) {
      newLayout = removeTabFromTile(newLayout, removedId, tabs, width, height)
    }

    // Add new tabs - each gets its own tile (no auto-grouping by project)
    for (const addedTab of addedTabs) {
      const existingIds = newLayout.map(l => l.id)
      const activeId = existingIds.length > 0 ? existingIds[existingIds.length - 1] : null
      newLayout = addTileToLayout(newLayout, addedTab.id, activeId, width, height)
    }

    if (tabs.length > 0) {
      activeTabIdRef.current = tabs[tabs.length - 1].id
    }

    return validateLayout(newLayout, tabs, width, height)
  }, [layout, tabs, containerSizeRef])

  effectiveLayoutRef.current = effectiveLayout

  useEffect(() => {
    const layoutTabIds = getAllTabIdsFromLayout(layout.map(migrateTile))
    const effectiveTabIds = getAllTabIdsFromLayout(effectiveLayout)
    const idsMatch = layoutTabIds.size === effectiveTabIds.size &&
      [...layoutTabIds].every(id => effectiveTabIds.has(id))

    if (!idsMatch) {
      onLayoutChange(effectiveLayout)
    }
  }, [effectiveLayout, layout, onLayoutChange])

  return { effectiveLayout, effectiveLayoutRef, activeTabIdRef }
}

import React from 'react'
import type { DropZone, DropZoneType } from '../tiled-layout-utils.js'

const DROP_ZONE_LABELS: Record<DropZoneType, string> = {
  'swap': 'Swap',
  'split-top': 'Add Above',
  'split-bottom': 'Add Below',
  'split-left': 'Add Left',
  'split-right': 'Add Right'
}

interface DropZoneOverlayProps {
  currentDropZone: DropZone
  draggedSidebarProject: string | null
  swapLabel?: string
  GAP: number
  viewportSize: { width: number; height: number }
}

export function DropZoneOverlay({
  currentDropZone,
  draggedSidebarProject,
  swapLabel,
  GAP,
  viewportSize
}: DropZoneOverlayProps): React.ReactElement {
  let label: string
  if (currentDropZone.type === 'swap' && swapLabel) {
    label = swapLabel
  } else if (draggedSidebarProject) {
    label = currentDropZone.type === 'swap' ? 'Add as Tab' : `Open ${DROP_ZONE_LABELS[currentDropZone.type].replace('Add ', '')}`
  } else {
    label = DROP_ZONE_LABELS[currentDropZone.type]
  }

  let background: string
  if (draggedSidebarProject) {
    background = 'rgba(34, 197, 94, 0.35)'
  } else if (currentDropZone.type === 'swap') {
    background = 'rgba(var(--accent-rgb), 0.3)'
  } else {
    background = 'rgba(59, 130, 246, 0.35)'
  }

  return (
    <div
      className="drop-zone-overlay"
      style={{
        position: 'absolute',
        left: `${currentDropZone.bounds.x / 100 * viewportSize.width + GAP}px`,
        top: `${currentDropZone.bounds.y / 100 * viewportSize.height + GAP}px`,
        width: `${currentDropZone.bounds.width / 100 * viewportSize.width - GAP}px`,
        height: `${currentDropZone.bounds.height / 100 * viewportSize.height - GAP}px`,
        background,
        border: '2px dashed var(--accent)',
        borderRadius: 'var(--radius-sm)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        pointerEvents: 'none', zIndex: 1000, transition: 'all 100ms ease'
      }}
    >
      <span className="drop-zone-label" style={{
        fontSize: '13px', fontWeight: 600, color: 'white',
