 27→  theme,
 28→  focusedTabId,
 29→  onCloseTab,
 30→  onFocusTab,
 31→  layout,
 32→  onLayoutChange,
 33→  onOpenSessionAtPosition,
 34→  onAddTab,
 35→  onUndoCloseTab,
 36→  api
