 38→  const containerRef = useRef<HTMLDivElement>(null)
 39→  const containerSizeRef = useRef({ width: 1920, height: 1080 })
 40→  const [viewportSize, setViewportSize] = useState({ width: 1920, height: 1080 })
 41→  const onLayoutChangeRef = useRef(onLayoutChange)
 42→  onLayoutChangeRef.current = onLayoutChange
 43→
 44→  useEffect(() => {
 45→    const container = containerRef.current
 46→    if (!container) return
 47→
 48→    const resizeObserver = new ResizeObserver((entries) => {
 49→      for (const entry of entries) {
 50→        const { width, height } = entry.contentRect
 51→        if (width > 0 && height > 0) {
 52→          containerSizeRef.current = { width, height }
 53→          setViewportSize({ width, height })
 54→        }
 55→      }
 56→    })
 57→
 58→    resizeObserver.observe(container)
 59→    const rect = container.getBoundingClientRect()
 60→    if (rect.width > 0 && rect.height > 0) {
 61→      containerSizeRef.current = { width: rect.width, height: rect.height }
 62→      setViewportSize({ width: rect.width, height: rect.height })
 63→    }
 64→
 65→    return () => resizeObserver.disconnect()
 66→  }, [])
 67→
 68→  const [draggedTile, setDraggedTile] = useState<string | null>(null)
 69→  const [draggedSidebarProject, setDraggedSidebarProject] = useState<string | null>(null)
 70→  const [dropTarget, setDropTarget] = useState<string | null>(null)
 71→  const [currentDropZone, setCurrentDropZone] = useState<DropZone | null>(null)
 72→  const [tileResizing, setTileResizing] = useState<TileResizeState | null>(null)
 73→  const [hoveredEdge, setHoveredEdge] = useState<{ tileId: string; edge: string } | null>(null)
 74→
 75→  const { effectiveLayout, effectiveLayoutRef } = useEffectiveLayout(
 76→    layout, tabs, containerSizeRef, onLayoutChange
 77→  )
 78→
 79→  // Compute canvas width from tile positions, with padding so the rightmost edge is accessible
 80→  const CANVAS_PADDING = 180 // px of extra space past the rightmost tile for resize handles
 81→  const canvasWidth = useMemo(() => {
 82→    if (effectiveLayout.length === 0) return viewportSize.width
