134→
135→  const dragDropActions = {
136→    setDraggedTile,
137→    setDraggedSidebarProject,
138→    setDropTarget,
139→    setCurrentDropZone
140→  }
141→
142→  const handleDragStart = useHandleDragStart(setDraggedTile)
143→  const handleContainerDragOver = useHandleContainerDragOver(
144→    containerRef, effectiveLayout,
145→    { draggedTile, draggedSidebarProject },
146→    dragDropActions,
147→    clientToCanvasPercentRef
148→  )
149→  const handleContainerDragLeave = useHandleContainerDragLeave(containerRef, dragDropActions)
150→  const applyDropZone = useApplyDropZone(tabs, containerSizeRef)
151→  const handleContainerDrop = useHandleContainerDrop(
152→    containerRef, effectiveLayoutRef, containerSizeRef,
153→    tabs, onLayoutChange, applyDropZone, onOpenSessionAtPosition,
154→    dragDropActions,
155→    clientToCanvasPercentRef
156→  )
157→  const handleDragEnd = useHandleDragEnd(dragDropActions)
158→
159→  const getHighlightedEdges = useGetHighlightedEdges(effectiveLayout)
160→  const highlightedEdges = useHighlightedEdges(hoveredEdge, tileResizing, getHighlightedEdges)
161→
162→  if (tabs.length === 0) return null
163→
