166→      ref={containerRef}
167→      className={`terminal-tiled-custom${tileResizing ? ' is-resizing' : ''}${isPanning ? ' is-panning' : ''}`}
168→      style={{ flex: 1, padding: `${GAP}px`, overflow: 'hidden', background: 'var(--bg-base)', position: 'relative' }}
169→      onDragOver={handleContainerDragOver}
170→      onDragLeave={handleContainerDragLeave}
