export function useHandleContainerDrop(
  containerRef: MutableRefObject<HTMLDivElement | null>,
  effectiveLayoutRef: MutableRefObject<TileLayout[]>,
  containerSizeRef: MutableRefObject<{ width: number; height: number }>,
  tabs: OpenTab[],
  onLayoutChange: (layout: TileLayout[]) => void,
  applyDropZone: (layout: TileLayout[], draggedId: string, zone: DropZone) => TileLayout[],
  onOpenSessionAtPosition: ((projectPath: string, dropZone: DropZone | null, containerSize: { width: number, height: number }, currentLayout?: TileLayout[]) => void) | undefined,
  actions: DragDropActions,
  clientToCanvasPercentRef?: MutableRefObject<ClientToCanvasPercent>
): (e: React.DragEvent) => void {
  const { setDraggedTile, setDraggedSidebarProject, setDropTarget, setCurrentDropZone } = actions

  return useCallback((e: React.DragEvent) => {
    e.preventDefault()

    const sidebarProjectPath = e.dataTransfer.getData('application/x-sidebar-project')
    const textPlainData = e.dataTransfer.getData('text/plain')
    const isSidebarDrag = e.dataTransfer.types.includes('application/x-sidebar-project')

    let dropZone: DropZone | null = null
    if (containerRef.current) {
      const { x: mouseX, y: mouseY } = clientToCanvasPercentRef?.current
        ? clientToCanvasPercentRef.current(e.clientX, e.clientY)
        : (() => { const rect = containerRef.current!.getBoundingClientRect(); return { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 } })()
      const currentLayout = effectiveLayoutRef.current
      dropZone = computeDropZone(currentLayout, null, mouseX, mouseY)
    }

    console.log('[TiledTerminalView] Drop event:', {
      sidebarProjectPath,
      textPlainData,
      isSidebarDrag,
      hasCallback: !!onOpenSessionAtPosition,
      dropZone,
      dataTypes: Array.from(e.dataTransfer.types)
    })

    const projectPath = sidebarProjectPath || (isSidebarDrag ? textPlainData : null)

    if (projectPath && onOpenSessionAtPosition) {
      // Pass the effective layout so handleOpenSessionAtPosition uses the same layout
      // that computeDropZone used (avoids stale closure / state mismatch)
      const layoutForPosition = effectiveLayoutRef.current

      console.log('[TiledTerminalView] Calling onOpenSessionAtPosition with:', projectPath, dropZone, containerSizeRef.current, 'layoutTiles:', layoutForPosition.length)
      onOpenSessionAtPosition(projectPath, dropZone, containerSizeRef.current, layoutForPosition)
      setDraggedSidebarProject(null)
      setDropTarget(null)
      setCurrentDropZone(null)
      return
    }

    const sourceTileId = e.dataTransfer.getData('text/plain')

    if (sourceTileId && dropZone) {
      const newLayout = applyDropZone(effectiveLayoutRef.current, sourceTileId, dropZone)
      const validatedLayout = validateLayout(newLayout, tabs)
      onLayoutChange(validatedLayout)
    }

    setDraggedTile(null)
    setDropTarget(null)
    setCurrentDropZone(null)
  }, [containerRef, effectiveLayoutRef, containerSizeRef, tabs, onLayoutChange, applyDropZone, onOpenSessionAtPosition, setDraggedTile, setDraggedSidebarProject, setDropTarget, setCurrentDropZone, clientToCanvasPercentRef])
}

export function useHandleDragEnd(
  actions: DragDropActions
): () => void {
  const { setDraggedTile, setDraggedSidebarProject, setDropTarget, setCurrentDropZone } = actions

  return useCallback(() => {
    setDraggedTile(null)
    setDraggedSidebarProject(null)
    setDropTarget(null)
    setCurrentDropZone(null)
  }, [setDraggedTile, setDraggedSidebarProject, setDropTarget, setCurrentDropZone])
}

export interface TileLayout {
  id: string
  tabIds: string[]    // Ordered list of OpenTab IDs in this tile
  activeTabId: string // Currently visible sub-tab
  x: number      // Left position as percentage (0-100)
  y: number      // Top position as percentage (0-100)
  width: number  // Width as percentage (0-100)
  height: number // Height as percentage (0-100)
}

export interface OpenTab {
  id: string
  projectPath: string
  sessionId?: string
  title: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}

export type DropZoneType =
  | 'swap'
  | 'split-top'
  | 'split-bottom'
  | 'split-left'
  | 'split-right'

export interface DropZone {
  type: DropZoneType
  targetTileId: string
  bounds: { x: number; y: number; width: number; height: number }
}

interface TileRow {
  y: number
  height: number
  tiles: TileLayout[]
}

export const MIN_SIZE = 10
const EPSILON = 1

function tilesOverlap(a: TileLayout, b: TileLayout): boolean {
  const overlapX = a.x < b.x + b.width && a.x + a.width > b.x
  const overlapY = a.y < b.y + b.height && a.y + a.height > b.y
  return overlapX && overlapY
}

function detectRows(layout: TileLayout[]): TileRow[] {
  const rowMap = new Map<string, TileLayout[]>()

  for (const tile of layout) {
    const key = `${Math.round(tile.y)}-${Math.round(tile.height)}`
    const existing = rowMap.get(key) || []
    existing.push(tile)
    rowMap.set(key, existing)
  }

  const rows: TileRow[] = []
  for (const tiles of rowMap.values()) {
    rows.push({
      y: tiles[0].y,
      height: tiles[0].height,
      tiles: tiles.sort((a, b) => a.x - b.x)
    })
  }

  return rows.sort((a, b) => a.y - b.y)
}

function findAdjacentTile(layout: TileLayout[], removed: TileLayout): TileLayout | null {
  const rightNeighbor = layout.find(t =>
    Math.abs(t.x - (removed.x + removed.width)) < EPSILON &&
    t.y < removed.y + removed.height + EPSILON &&
    t.y + t.height > removed.y - EPSILON
  )
  if (rightNeighbor) return rightNeighbor

  const bottomNeighbor = layout.find(t =>
    Math.abs(t.y - (removed.y + removed.height)) < EPSILON &&
    t.x < removed.x + removed.width + EPSILON &&
    t.x + t.width > removed.x - EPSILON
  )
  if (bottomNeighbor) return bottomNeighbor

  const leftNeighbor = layout.find(t =>
    Math.abs(t.x + t.width - removed.x) < EPSILON &&
    t.y < removed.y + removed.height + EPSILON &&
    t.y + t.height > removed.y - EPSILON
  )
  if (leftNeighbor) return leftNeighbor

  const topNeighbor = layout.find(t =>
    Math.abs(t.y + t.height - removed.y) < EPSILON &&
    t.x < removed.x + removed.width + EPSILON &&
    t.x + t.width > removed.x - EPSILON
  )
  return topNeighbor || null
}

/** Expand a tile into the removed tile's space along their shared edge only.
 *  Returns null if the expansion would overlap any other remaining tile. */
function expandAlongSharedEdge(
  tile: TileLayout,
  removed: TileLayout,
  remaining: TileLayout[]
): TileLayout | null {
  let candidate: TileLayout | null = null

  // Check which edge is shared and expand only in that direction
  if (Math.abs(tile.x + tile.width - removed.x) < EPSILON) {
    // tile is to the LEFT of removed → expand width rightward
    candidate = { ...tile, width: tile.width + removed.width }
  } else if (Math.abs(removed.x + removed.width - tile.x) < EPSILON) {
    // tile is to the RIGHT of removed → expand leftward
    candidate = { ...tile, x: removed.x, width: tile.width + removed.width }
  } else if (Math.abs(tile.y + tile.height - removed.y) < EPSILON) {
    // tile is ABOVE removed → expand height downward
    candidate = { ...tile, height: tile.height + removed.height }
  } else if (Math.abs(removed.y + removed.height - tile.y) < EPSILON) {
    // tile is BELOW removed → expand upward
    candidate = { ...tile, y: removed.y, height: tile.height + removed.height }
  }

  if (!candidate) return null

  // Verify the expansion doesn't overlap any other tile
  for (const other of remaining) {
    if (other.id === tile.id) continue
    if (tilesOverlap(candidate, other)) return null
  }

  return candidate
}

function findOptimalGrid(count: number, containerWidth: number, containerHeight: number): { rows: number; cols: number } {
  if (count <= 0) return { rows: 0, cols: 0 }
  if (count === 1) return { rows: 1, cols: 1 }

  let bestRows = 1
  let bestCols = count
  let bestDeviation = Infinity

  for (let rows = 1; rows <= count; rows++) {
    const cols = Math.ceil(count / rows)
    const tileWidth = containerWidth / cols
    const tileHeight = containerHeight / rows
    const tileAspect = tileWidth / tileHeight
    const deviation = Math.abs(Math.log(tileAspect))

    if (deviation < bestDeviation) {
      bestDeviation = deviation
      bestRows = rows
      bestCols = cols
    }
  }

  return { rows: bestRows, cols: bestCols }
}

function makeTile(id: string, x: number, y: number, width: number, height: number, tabIds?: string[], activeTabId?: string): TileLayout {
  const tIds = tabIds || [id]
  return { id, tabIds: tIds, activeTabId: activeTabId || tIds[0], x, y, width, height }
}

export function generateDefaultLayout(tabs: OpenTab[], containerWidth = 1920, containerHeight = 1080): TileLayout[] {
  // Each tab gets its own tile (no grouping by project)
  const count = tabs.length
  if (count === 0) return []
  if (count === 1) {
    return [makeTile(tabs[0].id, 0, 0, 100, 100)]
  }

  // For 3+ tiles, lay out in a single horizontal row where each tile gets
  // at least 50% viewport width (canvas extends beyond viewport)
  if (count >= 3) {
    const layout: TileLayout[] = []
    const tileWidth = 50  // Each tile gets 50% of viewport width
    for (let i = 0; i < count; i++) {
      layout.push(makeTile(tabs[i].id, i * tileWidth, 0, tileWidth, 100))
    }
    return layout
  }

  const { rows, cols } = findOptimalGrid(count, containerWidth, containerHeight)
  const layout: TileLayout[] = []
  const colWidth = 100 / cols
  const rowHeight = 100 / rows
  const fullRows = Math.floor(count / cols)
  const lastRowCount = count % cols

  let tabIndex = 0

  for (let row = 0; row < fullRows; row++) {
    for (let col = 0; col < cols; col++) {
      layout.push(makeTile(tabs[tabIndex].id, col * colWidth, row * rowHeight, colWidth, rowHeight))
      tabIndex++
    }
  }

  if (lastRowCount > 0) {
    const lastRowColWidth = 100 / lastRowCount
    for (let col = 0; col < lastRowCount; col++) {
      layout.push(makeTile(tabs[tabIndex].id, col * lastRowColWidth, fullRows * rowHeight, lastRowColWidth, rowHeight))
      tabIndex++
    }
  }

  return layout
}

export function validateLayout(layout: TileLayout[], tabs: OpenTab[], containerWidth = 1920, containerHeight = 1080): TileLayout[] {
  const tabIdSet = new Set(tabs.map(t => t.id))

  // Filter stale tabIds that no longer correspond to actual tabs
  let cleaned = layout.map(tile => {
    const validTabIds = (tile.tabIds || []).filter(id => tabIdSet.has(id))
    if (validTabIds.length === tile.tabIds?.length) return tile
    const activeTabId = validTabIds.includes(tile.activeTabId) ? tile.activeTabId : validTabIds[0]
    return { ...tile, tabIds: validTabIds, activeTabId: activeTabId || tile.activeTabId }
  })

  // Remove tiles that have no valid tabs and reclaim their space
  let emptyTileIds = cleaned.filter(t => t.tabIds.length === 0).map(t => t.id)
  for (const emptyId of emptyTileIds) {
    cleaned = removeTilePreservingStructure(cleaned, emptyId, tabs, containerWidth, containerHeight)
  }

  for (const tile of cleaned) {
    if (tile.x < 0 || tile.y < 0 ||
        tile.y + tile.height > 100.5 ||
        tile.width < 5 || tile.height < 5) {
      console.warn('Detected out-of-bounds tile, resetting to default layout', tile)
      return generateDefaultLayout(tabs, containerWidth, containerHeight)
    }
    if (!tile.tabIds || tile.tabIds.length === 0) {
      console.warn('Detected tile with empty tabIds, resetting to default layout', tile)
      return generateDefaultLayout(tabs, containerWidth, containerHeight)
    }
    if (!tile.activeTabId || !tile.tabIds.includes(tile.activeTabId)) {
      console.warn('Detected tile with invalid activeTabId, fixing', tile)
      tile.activeTabId = tile.tabIds[0]
    }
  }

  for (let i = 0; i < cleaned.length; i++) {
    for (let j = i + 1; j < cleaned.length; j++) {
      if (tilesOverlap(cleaned[i], cleaned[j])) {
        console.warn('Detected overlapping tiles:', cleaned[i], cleaned[j])
      }
    }
  }
  return cleaned
}

export function removeTilePreservingStructure(
  layout: TileLayout[],
  removedTileId: string,
  tabs: OpenTab[],
  containerWidth: number,
  containerHeight: number
): TileLayout[] {
  const removed = layout.find(t => t.id === removedTileId)
  if (!removed) return layout

  const remaining = layout.filter(t => t.id !== removedTileId)
  if (remaining.length === 0) return []

  const sameRow = remaining.filter(t =>
    Math.abs(t.y - removed.y) < EPSILON &&
    Math.abs(t.height - removed.height) < EPSILON
  )

  const sameColumn = remaining.filter(t =>
    Math.abs(t.x - removed.x) < EPSILON &&
    Math.abs(t.width - removed.width) < EPSILON
  )

  if (sameRow.length > 0) {
    // Only expand tiles directly adjacent to the removed tile to avoid
    // repositioning distant tiles over non-sameRow tiles (causing overlaps)
    const leftNeighbor = sameRow.find(t => Math.abs(t.x + t.width - removed.x) < EPSILON)
    const rightNeighbor = sameRow.find(t => Math.abs(t.x - (removed.x + removed.width)) < EPSILON)
    const neighbors = [leftNeighbor, rightNeighbor].filter(Boolean) as TileLayout[]

    if (neighbors.length > 0) {
      const extraWidthPerTile = removed.width / neighbors.length
      return remaining.map(t => {
        if (leftNeighbor && t.id === leftNeighbor.id) {
          return { ...t, width: t.width + extraWidthPerTile }
        }
        if (rightNeighbor && t.id === rightNeighbor.id) {
          return { ...t, x: t.x - extraWidthPerTile, width: t.width + extraWidthPerTile }
        }
        return t
      })
    }
  }

  if (sameColumn.length > 0) {
    // Only expand tiles directly adjacent to the removed tile
    const topNeighbor = sameColumn.find(t => Math.abs(t.y + t.height - removed.y) < EPSILON)
    const bottomNeighbor = sameColumn.find(t => Math.abs(t.y - (removed.y + removed.height)) < EPSILON)
    const neighbors = [topNeighbor, bottomNeighbor].filter(Boolean) as TileLayout[]

    if (neighbors.length > 0) {
      const extraHeightPerTile = removed.height / neighbors.length
      return remaining.map(t => {
        if (topNeighbor && t.id === topNeighbor.id) {
          return { ...t, height: t.height + extraHeightPerTile }
        }
        if (bottomNeighbor && t.id === bottomNeighbor.id) {
          return { ...t, y: t.y - extraHeightPerTile, height: t.height + extraHeightPerTile }
        }
        return t
      })
    }
  }

  // Fallback: find ALL tiles sharing an edge with the removed tile and expand them.
  // Group by which edge they share (left, right, top, bottom of the removed tile).
  const leftOf = remaining.filter(t => Math.abs(t.x + t.width - removed.x) < EPSILON &&
    t.y < removed.y + removed.height - EPSILON && t.y + t.height > removed.y + EPSILON)
  const rightOf = remaining.filter(t => Math.abs(t.x - (removed.x + removed.width)) < EPSILON &&
    t.y < removed.y + removed.height - EPSILON && t.y + t.height > removed.y + EPSILON)
  const above = remaining.filter(t => Math.abs(t.y + t.height - removed.y) < EPSILON &&
    t.x < removed.x + removed.width - EPSILON && t.x + t.width > removed.x + EPSILON)
  const below = remaining.filter(t => Math.abs(t.y - (removed.y + removed.height)) < EPSILON &&
    t.x < removed.x + removed.width - EPSILON && t.x + t.width > removed.x + EPSILON)

  // Try expanding tiles on one side into the gap. Prefer the side with tiles
  // that together span the full edge (so no gaps remain).
  const tryExpand = (tiles: TileLayout[], dir: 'right' | 'left' | 'down' | 'up'): TileLayout[] | null => {
    if (tiles.length === 0) return null
    const expandedIds = new Set(tiles.map(t => t.id))
    const result = remaining.map(t => {
      if (!expandedIds.has(t.id)) return t
      switch (dir) {
        case 'right': return { ...t, width: t.width + removed.width }
        case 'left': return { ...t, x: removed.x, width: t.width + removed.width }
        case 'down': return { ...t, height: t.height + removed.height }
        case 'up': return { ...t, y: removed.y, height: t.height + removed.height }
      }
    })
    // Verify no overlaps
    for (let i = 0; i < result.length; i++) {
      for (let j = i + 1; j < result.length; j++) {
        if (tilesOverlap(result[i], result[j])) return null
      }
    }
    return result
  }

  const expanded = tryExpand(leftOf, 'right') || tryExpand(rightOf, 'left') ||
                   tryExpand(above, 'down') || tryExpand(below, 'up')
  if (expanded) return expanded

  // If nothing else worked, just leave the remaining tiles as-is.
  // A gap is better than resetting the entire layout.
  return remaining
}

export function splitTile(
  layout: TileLayout[],
  targetTileId: string,
  newTileId: string,
  direction: 'top' | 'bottom' | 'left' | 'right'
): TileLayout[] {
  const target = layout.find(t => t.id === targetTileId)
  if (!target) return layout

  const isHorizontal = direction === 'top' || direction === 'bottom'
  const newLayout = layout.filter(t => t.id !== targetTileId)

  // The target tile keeps its tabIds; the new tile gets a single tab
  const targetTabIds = target.tabIds || [targetTileId]
  const targetActiveTabId = target.activeTabId || targetTabIds[0]

  if (isHorizontal) {
    const halfHeight = target.height / 2
    const topTileId = direction === 'top' ? newTileId : targetTileId
    const bottomTileId = direction === 'bottom' ? newTileId : targetTileId
    newLayout.push(
      makeTile(topTileId, target.x, target.y, target.width, halfHeight,
        topTileId === targetTileId ? targetTabIds : [newTileId],
        topTileId === targetTileId ? targetActiveTabId : newTileId),
      makeTile(bottomTileId, target.x, target.y + halfHeight, target.width, halfHeight,
        bottomTileId === targetTileId ? targetTabIds : [newTileId],
        bottomTileId === targetTileId ? targetActiveTabId : newTileId)
    )
  } else {
    const halfWidth = target.width / 2
    const leftTileId = direction === 'left' ? newTileId : targetTileId
    const rightTileId = direction === 'right' ? newTileId : targetTileId
    newLayout.push(
      makeTile(leftTileId, target.x, target.y, halfWidth, target.height,
        leftTileId === targetTileId ? targetTabIds : [newTileId],
        leftTileId === targetTileId ? targetActiveTabId : newTileId),
      makeTile(rightTileId, target.x + halfWidth, target.y, halfWidth, target.height,
        rightTileId === targetTileId ? targetTabIds : [newTileId],
        rightTileId === targetTileId ? targetActiveTabId : newTileId)
    )
  }

  return newLayout
}

export function addTileToLayout(
  layout: TileLayout[],
  newTileId: string,
  activeTabId: string | null,
  containerWidth: number,
  containerHeight: number
): TileLayout[] {
  if (layout.length === 0) {
    return [makeTile(newTileId, 0, 0, 100, 100)]
  }

  // For 1 tile, split it so both tiles stay on-screen
  if (layout.length === 1) {
    const tile = layout[0]
    const tileAspect = (tile.width / 100 * containerWidth) / (tile.height / 100 * containerHeight)
    const direction = tileAspect > 1 ? 'right' : 'bottom'
    return splitTile(layout, tile.id, newTileId, direction)
  }

  // For 2+ tiles, always append to the right of the rightmost edge.
  // Never split or redistribute existing tiles — that destroys custom layouts.
  const rightmostEdge = Math.max(...layout.map(t => t.x + t.width))
  return [...layout, makeTile(newTileId, rightmostEdge, 0, 50, 100)]
}

export function computeDropZone(
  layout: TileLayout[],
  draggedTileId: string | null,
  mouseX: number,
  mouseY: number
): DropZone | null {
  // 30% edge threshold makes it easier to trigger split zones
  const EDGE_THRESHOLD = 0.30

  const targetTile = layout.find(t =>
    t.id !== draggedTileId &&
    mouseX >= t.x && mouseX <= t.x + t.width &&
    mouseY >= t.y && mouseY <= t.y + t.height
  )

  if (!targetTile) return null

  const relX = (mouseX - targetTile.x) / targetTile.width
  const relY = (mouseY - targetTile.y) / targetTile.height

  let type: DropZoneType = 'swap'
  let bounds = { x: targetTile.x, y: targetTile.y, width: targetTile.width, height: targetTile.height }

  // Calculate distances to each edge (0 = at edge, 0.5 = at center)
  const distToLeft = relX
  const distToRight = 1 - relX
  const distToTop = relY
  const distToBottom = 1 - relY

  // Find the closest edge
  const minDist = Math.min(distToLeft, distToRight, distToTop, distToBottom)

  // Only trigger split zone if we're within the threshold
  if (minDist < EDGE_THRESHOLD) {
    if (minDist === distToTop) {
      type = 'split-top'
      bounds = { x: targetTile.x, y: targetTile.y, width: targetTile.width, height: targetTile.height / 2 }
    } else if (minDist === distToBottom) {
      type = 'split-bottom'
      bounds = { x: targetTile.x, y: targetTile.y + targetTile.height / 2, width: targetTile.width, height: targetTile.height / 2 }
    } else if (minDist === distToLeft) {
      type = 'split-left'
      bounds = { x: targetTile.x, y: targetTile.y, width: targetTile.width / 2, height: targetTile.height }
    } else if (minDist === distToRight) {
      type = 'split-right'
      bounds = { x: targetTile.x + targetTile.width / 2, y: targetTile.y, width: targetTile.width / 2, height: targetTile.height }
    }
  }

  return { type, targetTileId: targetTile.id, bounds }
}

/** Migrate a legacy tile (without tabIds) to the new format */
export function migrateTile(tile: TileLayout): TileLayout {
  if (tile.tabIds && tile.tabIds.length > 0) return tile
  return { ...tile, tabIds: [tile.id], activeTabId: tile.activeTabId || tile.id }
}

/** Add a tab to an existing tile's tabIds */
export function addTabToExistingTile(layout: TileLayout[], tileId: string, tabId: string): TileLayout[] {
  return layout.map(tile => {
    if (tile.id === tileId) {
      const tabIds = [...tile.tabIds, tabId]
      return { ...tile, tabIds, activeTabId: tabId }
    }
    return tile
  })
}

/** Find a tile that contains a tab for the given project */
export function findTileForProject(layout: TileLayout[], tabs: OpenTab[], projectPath: string): TileLayout | undefined {
  return layout.find(tile =>
    tile.tabIds.some(tabId => {
      const tab = tabs.find(t => t.id === tabId)
      return tab && tab.projectPath === projectPath
    })
  )
}

/** Remove a tab from its tile. If the tile becomes empty, remove the tile and reclaim space. */
export function removeTabFromTile(
  layout: TileLayout[],
  tabId: string,
  tabs: OpenTab[],
  containerWidth: number,
  containerHeight: number
): TileLayout[] {
  const tile = layout.find(t => t.tabIds.includes(tabId))
  if (!tile) return layout

  const newTabIds = tile.tabIds.filter(id => id !== tabId)
  if (newTabIds.length === 0) {
    // Tile is empty, remove it entirely and reclaim space
    return removeTilePreservingStructure(layout, tile.id, tabs, containerWidth, containerHeight)
  }

  // Update the tile with the remaining tabs
  const newActiveTabId = tile.activeTabId === tabId ? newTabIds[newTabIds.length - 1] : tile.activeTabId
  return layout.map(t => {
    if (t.id === tile.id) {
      return { ...t, tabIds: newTabIds, activeTabId: newActiveTabId }
    }
    return t
  })
}

/** Get all tab IDs across all tiles */
export function getAllTabIdsFromLayout(layout: TileLayout[]): Set<string> {
  const ids = new Set<string>()
  for (const tile of layout) {
    for (const tabId of tile.tabIds) {
      ids.add(tabId)
    }
  }
  return ids
}

export function findTilesOnDivider(
  position: number,
  isVertical: boolean,
  side: 'before' | 'after',
  layout: TileLayout[]
): TileLayout[] {
  const EPSILON = 1
  return layout.filter(tile => {
    if (isVertical) {
      if (side === 'before') {
        return Math.abs(tile.x + tile.width - position) < EPSILON
      } else {
        return Math.abs(tile.x - position) < EPSILON
      }
    } else {
      if (side === 'before') {
        return Math.abs(tile.y + tile.height - position) < EPSILON
      } else {
        return Math.abs(tile.y - position) < EPSILON
      }
    }
  })
}

/** Find tiles on a divider that form a contiguous segment with the anchor tile.
 *  For horizontal dividers, contiguity is horizontal adjacency.
 *  For vertical dividers, contiguity is vertical adjacency. */
export function findContiguousTilesOnDivider(
  position: number,
  isVertical: boolean,
  side: 'before' | 'after',
  layout: TileLayout[],
  anchorTile: TileLayout
): TileLayout[] {
  const allOnDivider = findTilesOnDivider(position, isVertical, side, layout)
  if (allOnDivider.length <= 1) return allOnDivider
  if (!allOnDivider.find(t => t.id === anchorTile.id)) return allOnDivider

  const group = new Set<string>([anchorTile.id])
  let changed = true
  while (changed) {
    changed = false
    for (const tile of allOnDivider) {
      if (group.has(tile.id)) continue
      for (const memberId of group) {
        const member = allOnDivider.find(t => t.id === memberId)!
        const adjacent = isVertical
          ? (Math.abs(tile.y + tile.height - member.y) < EPSILON || Math.abs(member.y + member.height - tile.y) < EPSILON)
          : (Math.abs(tile.x + tile.width - member.x) < EPSILON || Math.abs(member.x + member.width - tile.x) < EPSILON)
        if (adjacent) {
          group.add(tile.id)
          changed = true
          break
        }
      }
    }
  }
  return allOnDivider.filter(t => group.has(t.id))
}

/** Find tiles on the opposite side of a divider that overlap with the given group's perpendicular range */
export function findOverlappingTilesOnDivider(
  position: number,
  isVertical: boolean,
  side: 'before' | 'after',
  layout: TileLayout[],
  groupTiles: TileLayout[]
): TileLayout[] {
  if (groupTiles.length === 0) return []
  const allOnDivider = findTilesOnDivider(position, isVertical, side, layout)
  if (isVertical) {
    const minY = Math.min(...groupTiles.map(t => t.y))
    const maxY = Math.max(...groupTiles.map(t => t.y + t.height))
    return allOnDivider.filter(t => t.y + EPSILON < maxY && t.y + t.height > minY + EPSILON)
  } else {
    const minX = Math.min(...groupTiles.map(t => t.x))
    const maxX = Math.max(...groupTiles.map(t => t.x + t.width))
    return allOnDivider.filter(t => t.x + EPSILON < maxX && t.x + t.width > minX + EPSILON)
  }
}

import { useCallback, MutableRefObject } from 'react'
import type { TileLayout, DropZone } from '../tiled-layout-utils.js'
import {
  computeDropZone,
  validateLayout,
  removeTilePreservingStructure,
  splitTile,
  addTabToExistingTile
} from '../tiled-layout-utils.js'
import type { OpenTab, ClientToCanvasPercent } from './types.js'

interface DragDropState {
  draggedTile: string | null
  draggedSidebarProject: string | null
  dropTarget: string | null
  currentDropZone: DropZone | null
}

interface DragDropActions {
  setDraggedTile: (id: string | null) => void
  setDraggedSidebarProject: (id: string | null) => void
  setDropTarget: (id: string | null) => void
  setCurrentDropZone: (zone: DropZone | null) => void
}

export function useHandleDragStart(
  setDraggedTile: (id: string | null) => void
): (e: React.DragEvent, tileId: string) => void {
  return useCallback((e: React.DragEvent, tileId: string) => {
    e.dataTransfer.setData('text/plain', tileId)
    e.dataTransfer.effectAllowed = 'move'
    setDraggedTile(tileId)
  }, [setDraggedTile])
}

export function useHandleContainerDragOver(
  containerRef: MutableRefObject<HTMLDivElement | null>,
  effectiveLayout: TileLayout[],
  state: Pick<DragDropState, 'draggedTile' | 'draggedSidebarProject'>,
  actions: Pick<DragDropActions, 'setDraggedSidebarProject' | 'setDropTarget' | 'setCurrentDropZone'>,
  clientToCanvasPercentRef?: MutableRefObject<ClientToCanvasPercent>
): (e: React.DragEvent) => void {
  const { draggedTile, draggedSidebarProject } = state
  const { setDraggedSidebarProject, setDropTarget, setCurrentDropZone } = actions

  return useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.dataTransfer.dropEffect = 'move'

    if (!containerRef.current) return

    const isSidebarProjectDrag = e.dataTransfer.types.includes('application/x-sidebar-project')

    if (isSidebarProjectDrag) {
      if (!draggedSidebarProject) {
        setDraggedSidebarProject('pending')
      }

      const { x: mouseX, y: mouseY } = clientToCanvasPercentRef?.current
        ? clientToCanvasPercentRef.current(e.clientX, e.clientY)
        : (() => { const rect = containerRef.current!.getBoundingClientRect(); return { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 } })()

      const zone = computeDropZone(effectiveLayout, null, mouseX, mouseY)
      setCurrentDropZone(zone)
      setDropTarget(zone?.targetTileId || null)
      return
    }

    if (!draggedTile) return

    const { x: mouseX, y: mouseY } = clientToCanvasPercentRef?.current
      ? clientToCanvasPercentRef.current(e.clientX, e.clientY)
      : (() => { const rect = containerRef.current!.getBoundingClientRect(); return { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 } })()

    const zone = computeDropZone(effectiveLayout, draggedTile, mouseX, mouseY)
    setCurrentDropZone(zone)
    setDropTarget(zone?.targetTileId || null)
  }, [containerRef, draggedTile, draggedSidebarProject, effectiveLayout, setDraggedSidebarProject, setDropTarget, setCurrentDropZone, clientToCanvasPercentRef])
}

export function useHandleContainerDragLeave(
  containerRef: MutableRefObject<HTMLDivElement | null>,
  actions: Pick<DragDropActions, 'setDraggedSidebarProject' | 'setDropTarget' | 'setCurrentDropZone'>
): (e: React.DragEvent) => void {
  const { setDraggedSidebarProject, setDropTarget, setCurrentDropZone } = actions

  return useCallback((e: React.DragEvent) => {
    const rect = containerRef.current?.getBoundingClientRect()
    if (rect) {
      const { clientX, clientY } = e
      if (clientX < rect.left || clientX > rect.right || clientY < rect.top || clientY > rect.bottom) {
        setCurrentDropZone(null)
        setDropTarget(null)
        setDraggedSidebarProject(null)
      }
    }
  }, [containerRef, setDraggedSidebarProject, setDropTarget, setCurrentDropZone])
}

export function useApplyDropZone(
  tabs: OpenTab[],
  containerSizeRef: MutableRefObject<{ width: number; height: number }>
): (layout: TileLayout[], draggedId: string, zone: DropZone) => TileLayout[] {
  return useCallback((layout: TileLayout[], draggedId: string, zone: DropZone): TileLayout[] => {
    const { width, height } = containerSizeRef.current

    if (zone.type === 'swap') {
      const sourceTile = layout.find(t => t.id === draggedId)
      const targetTile = layout.find(t => t.id === zone.targetTileId)

      if (sourceTile && targetTile) {
        // Check if source and target share a project → merge tabs
        const sourceProject = sourceTile.tabIds
          .map(id => tabs.find(t => t.id === id)?.projectPath)
          .find(p => p != null)
        const targetProject = targetTile.tabIds
          .map(id => tabs.find(t => t.id === id)?.projectPath)
          .find(p => p != null)

        if (sourceProject && sourceProject === targetProject) {
          // Merge: add source tabs into target tile, then remove source tile
          let merged = layout
          for (const tabId of sourceTile.tabIds) {
            merged = addTabToExistingTile(merged, targetTile.id, tabId)
          }
          return removeTilePreservingStructure(merged, draggedId, tabs, width, height)
        }

        // Different projects → swap positions
        return layout.map(tile => {
          if (tile.id === draggedId) {
            return { ...tile, x: targetTile.x, y: targetTile.y, width: targetTile.width, height: targetTile.height }
          }
          if (tile.id === zone.targetTileId) {
            return { ...tile, x: sourceTile.x, y: sourceTile.y, width: sourceTile.width, height: sourceTile.height }
          }
          return tile
        })
      }
      return layout
    }

    const direction = zone.type.replace('split-', '') as 'top' | 'bottom' | 'left' | 'right'
    // For drag operations, just remove the tile without expanding neighbors.
    // The tile is being moved, not deleted — expansion would distort the layout.
    const withoutDragged = layout.filter(t => t.id !== draggedId)
    return splitTile(withoutDragged, zone.targetTileId, draggedId, direction)
  }, [tabs, containerSizeRef])
}

export function useHandleContainerDrop(
  containerRef: MutableRefObject<HTMLDivElement | null>,
  effectiveLayoutRef: MutableRefObject<TileLayout[]>,
  containerSizeRef: MutableRefObject<{ width: number; height: number }>,
  tabs: OpenTab[],
  onLayoutChange: (layout: TileLayout[]) => void,
  applyDropZone: (layout: TileLayout[], draggedId: string, zone: DropZone) => TileLayout[],
  onOpenSessionAtPosition: ((projectPath: string, dropZone: DropZone | null, containerSize: { width: number, height: number }, currentLayout?: TileLayout[]) => void) | undefined,
  actions: DragDropActions,
  clientToCanvasPercentRef?: MutableRefObject<ClientToCanvasPercent>
): (e: React.DragEvent) => void {
  const { setDraggedTile, setDraggedSidebarProject, setDropTarget, setCurrentDropZone } = actions

  return useCallback((e: React.DragEvent) => {
    e.preventDefault()

    const sidebarProjectPath = e.dataTransfer.getData('application/x-sidebar-project')
    const textPlainData = e.dataTransfer.getData('text/plain')
    const isSidebarDrag = e.dataTransfer.types.includes('application/x-sidebar-project')

    let dropZone: DropZone | null = null
    if (containerRef.current) {
      const { x: mouseX, y: mouseY } = clientToCanvasPercentRef?.current
        ? clientToCanvasPercentRef.current(e.clientX, e.clientY)
        : (() => { const rect = containerRef.current!.getBoundingClientRect(); return { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 } })()
      const currentLayout = effectiveLayoutRef.current
      dropZone = computeDropZone(currentLayout, null, mouseX, mouseY)
    }

    console.log('[TiledTerminalView] Drop event:', {
      sidebarProjectPath,
      textPlainData,
      isSidebarDrag,
      hasCallback: !!onOpenSessionAtPosition,
      dropZone,
      dataTypes: Array.from(e.dataTransfer.types)
    })

    const projectPath = sidebarProjectPath || (isSidebarDrag ? textPlainData : null)

    if (projectPath && onOpenSessionAtPosition) {
      // Pass the effective layout so handleOpenSessionAtPosition uses the same layout
      // that computeDropZone used (avoids stale closure / state mismatch)
      const layoutForPosition = effectiveLayoutRef.current

      console.log('[TiledTerminalView] Calling onOpenSessionAtPosition with:', projectPath, dropZone, containerSizeRef.current, 'layoutTiles:', layoutForPosition.length)
      onOpenSessionAtPosition(projectPath, dropZone, containerSizeRef.current, layoutForPosition)
      setDraggedSidebarProject(null)
      setDropTarget(null)
      setCurrentDropZone(null)
      return
    }

    const sourceTileId = e.dataTransfer.getData('text/plain')

    if (sourceTileId && dropZone) {
      const newLayout = applyDropZone(effectiveLayoutRef.current, sourceTileId, dropZone)
      const validatedLayout = validateLayout(newLayout, tabs)
      onLayoutChange(validatedLayout)
    }

    setDraggedTile(null)
    setDropTarget(null)
    setCurrentDropZone(null)
  }, [containerRef, effectiveLayoutRef, containerSizeRef, tabs, onLayoutChange, applyDropZone, onOpenSessionAtPosition, setDraggedTile, setDraggedSidebarProject, setDropTarget, setCurrentDropZone, clientToCanvasPercentRef])
}

export function useHandleDragEnd(
  actions: DragDropActions
): () => void {
  const { setDraggedTile, setDraggedSidebarProject, setDropTarget, setCurrentDropZone } = actions

  return useCallback(() => {
    setDraggedTile(null)
    setDraggedSidebarProject(null)
    setDropTarget(null)
    setCurrentDropZone(null)
  }, [setDraggedTile, setDraggedSidebarProject, setDropTarget, setCurrentDropZone])
}

import { useEffect, useCallback, MutableRefObject } from 'react'
import type { TileLayout } from '../tiled-layout-utils.js'
import { findContiguousTilesOnDivider, findOverlappingTilesOnDivider, MIN_SIZE } from '../tiled-layout-utils.js'
import type { TileResizeState, ResizeEdge, ClientToCanvasPercent } from './types.js'

function getCursorForEdge(edge: string): string {
  switch (edge) {
    case 'right':
    case 'left':
      return 'ew-resize'
    case 'top':
    case 'bottom':
      return 'ns-resize'
    case 'top-left':
    case 'bottom-right':
      return 'nwse-resize'
    case 'top-right':
    case 'bottom-left':
      return 'nesw-resize'
    default:
      return 'default'
  }
}

export function useStartTileResize(
  effectiveLayout: TileLayout[],
  setTileResizing: (state: TileResizeState | null) => void,
  setHoveredEdge: (state: { tileId: string; edge: string } | null) => void
): (e: React.MouseEvent, tileId: string, edge: ResizeEdge) => void {
  return useCallback((e: React.MouseEvent, tileId: string, edge: ResizeEdge) => {
    e.preventDefault()
    e.stopPropagation()
    setHoveredEdge(null)
    const tile = effectiveLayout.find(t => t.id === tileId)
    if (tile) {
      const rightDivider = tile.x + tile.width
      const leftDivider = tile.x
      const bottomDivider = tile.y + tile.height
      const topDivider = tile.y

      // Find contiguous tile groups on each divider (only tiles connected to this tile)
      // then find overlapping tiles on the opposite side of each divider
      const tilesLeftOfRight = findContiguousTilesOnDivider(rightDivider, true, 'before', effectiveLayout, tile)
      const tilesRightOfRight = findOverlappingTilesOnDivider(rightDivider, true, 'after', effectiveLayout, tilesLeftOfRight)
      const tilesRightOfLeft = findContiguousTilesOnDivider(leftDivider, true, 'after', effectiveLayout, tile)
      const tilesLeftOfLeft = findOverlappingTilesOnDivider(leftDivider, true, 'before', effectiveLayout, tilesRightOfLeft)
      const tilesAboveBottom = findContiguousTilesOnDivider(bottomDivider, false, 'before', effectiveLayout, tile)
      const tilesBelowBottom = findOverlappingTilesOnDivider(bottomDivider, false, 'after', effectiveLayout, tilesAboveBottom)
      const tilesBelowTop = findContiguousTilesOnDivider(topDivider, false, 'after', effectiveLayout, tile)
      const tilesAboveTop = findOverlappingTilesOnDivider(topDivider, false, 'before', effectiveLayout, tilesBelowTop)

      setTileResizing({
        tileId,
        edge,
        startX: e.clientX,
        startY: e.clientY,
        startLayout: { ...tile },
        tilesLeftOfRightDivider: tilesLeftOfRight,
        tilesRightOfRightDivider: tilesRightOfRight,
        tilesLeftOfLeftDivider: tilesLeftOfLeft,
        tilesRightOfLeftDivider: tilesRightOfLeft,
        tilesAboveBottomDivider: tilesAboveBottom,
        tilesBelowBottomDivider: tilesBelowBottom,
        tilesAboveTopDivider: tilesAboveTop,
        tilesBelowTopDivider: tilesBelowTop,
        rightDividerPos: rightDivider,
        leftDividerPos: leftDivider,
        bottomDividerPos: bottomDivider,
        topDividerPos: topDivider
      })
    }
  }, [effectiveLayout, setTileResizing, setHoveredEdge])
}

export function useTileResizeEffect(
  tileResizing: TileResizeState | null,
  containerRef: MutableRefObject<HTMLDivElement | null>,
  effectiveLayoutRef: MutableRefObject<TileLayout[]>,
  onLayoutChangeRef: MutableRefObject<(layout: TileLayout[]) => void>,
  setTileResizing: (state: TileResizeState | null) => void,
  clientToCanvasPercentRef?: MutableRefObject<ClientToCanvasPercent>
): void {
  useEffect(() => {
    if (!tileResizing || !containerRef.current) return

    let rafId: number | null = null
    const handleTileResizeMove = (e: MouseEvent) => {
      if (!containerRef.current) return
      if (rafId !== null) return
      rafId = requestAnimationFrame(() => {
        rafId = null
        if (!containerRef.current) return
        const rect = containerRef.current.getBoundingClientRect()
        const {
          edge,
          tilesLeftOfRightDivider, tilesRightOfRightDivider,
          tilesLeftOfLeftDivider, tilesRightOfLeftDivider,
          tilesAboveBottomDivider, tilesBelowBottomDivider,
          tilesAboveTopDivider, tilesBelowTopDivider,
          rightDividerPos, leftDividerPos, bottomDividerPos, topDividerPos
        } = tileResizing
        const currentLayout = effectiveLayoutRef.current

        const canvasCoords = clientToCanvasPercentRef?.current
          ? clientToCanvasPercentRef.current(e.clientX, e.clientY)
          : { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 }
        const mouseXPercent = canvasCoords.x
        const mouseYPercent = canvasCoords.y

        const tileUpdates = new Map<string, TileLayout>()

        const moveVerticalDivider = (originalPos: number, tilesLeft: TileLayout[], tilesRight: TileLayout[]) => {
          if (tilesLeft.length === 0 && tilesRight.length === 0) return
          // Block left outer boundary (x=0) but allow free resize otherwise
          if (tilesLeft.length === 0 && originalPos < 1) return
          let minPos = 0
          let maxPos = Infinity
          tilesLeft.forEach(tile => { minPos = Math.max(minPos, tile.x + MIN_SIZE) })
          tilesRight.forEach(tile => { maxPos = Math.min(maxPos, tile.x + tile.width - MIN_SIZE) })
          const newPos = Math.max(minPos, Math.min(maxPos, mouseXPercent))

          tilesLeft.forEach(tile => {
            const currentTile = currentLayout.find(t => t.id === tile.id) || tile
            const existing = tileUpdates.get(tile.id) || { ...currentTile }
            existing.width = newPos - tile.x
            tileUpdates.set(tile.id, existing)
          })
          tilesRight.forEach(tile => {
            const currentTile = currentLayout.find(t => t.id === tile.id) || tile
            const existing = tileUpdates.get(tile.id) || { ...currentTile }
            const originalRight = tile.x + tile.width
            existing.x = newPos
            existing.width = originalRight - newPos
            tileUpdates.set(tile.id, existing)
          })
        }

        const moveHorizontalDivider = (originalPos: number, tilesAbove: TileLayout[], tilesBelow: TileLayout[]) => {
          if (tilesAbove.length === 0 && tilesBelow.length === 0) return
          let minPos = 0
          let maxPos = 100
          tilesAbove.forEach(tile => { minPos = Math.max(minPos, tile.y + MIN_SIZE) })
          tilesBelow.forEach(tile => { maxPos = Math.min(maxPos, tile.y + tile.height - MIN_SIZE) })
          const newPos = Math.max(minPos, Math.min(maxPos, mouseYPercent))

          tilesAbove.forEach(tile => {
            const currentTile = currentLayout.find(t => t.id === tile.id) || tile
            const existing = tileUpdates.get(tile.id) || { ...currentTile }
            existing.height = newPos - tile.y
            tileUpdates.set(tile.id, existing)
          })
          tilesBelow.forEach(tile => {
            const currentTile = currentLayout.find(t => t.id === tile.id) || tile
            const existing = tileUpdates.get(tile.id) || { ...currentTile }
            const originalBottom = tile.y + tile.height
            existing.y = newPos
            existing.height = originalBottom - newPos
            tileUpdates.set(tile.id, existing)
          })
        }

        switch (edge) {
          case 'right':
            moveVerticalDivider(rightDividerPos, tilesLeftOfRightDivider, tilesRightOfRightDivider)
            break
          case 'left':
            moveVerticalDivider(leftDividerPos, tilesLeftOfLeftDivider, tilesRightOfLeftDivider)
            break
          case 'bottom':
            moveHorizontalDivider(bottomDividerPos, tilesAboveBottomDivider, tilesBelowBottomDivider)
            break
          case 'top':
            moveHorizontalDivider(topDividerPos, tilesAboveTopDivider, tilesBelowTopDivider)
            break
          case 'top-left':
            moveHorizontalDivider(topDividerPos, tilesAboveTopDivider, tilesBelowTopDivider)
            moveVerticalDivider(leftDividerPos, tilesLeftOfLeftDivider, tilesRightOfLeftDivider)
            break
          case 'top-right':
            moveHorizontalDivider(topDividerPos, tilesAboveTopDivider, tilesBelowTopDivider)
            moveVerticalDivider(rightDividerPos, tilesLeftOfRightDivider, tilesRightOfRightDivider)
            break
          case 'bottom-left':
            moveHorizontalDivider(bottomDividerPos, tilesAboveBottomDivider, tilesBelowBottomDivider)
            moveVerticalDivider(leftDividerPos, tilesLeftOfLeftDivider, tilesRightOfLeftDivider)
            break
          case 'bottom-right':
            moveHorizontalDivider(bottomDividerPos, tilesAboveBottomDivider, tilesBelowBottomDivider)
            moveVerticalDivider(rightDividerPos, tilesLeftOfRightDivider, tilesRightOfRightDivider)
            break
        }

        const newLayout = currentLayout.map(tile => tileUpdates.get(tile.id) || tile)
        onLayoutChangeRef.current(newLayout)
      })
    }

    const handleTileResizeUp = () => {
      setTileResizing(null)
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    }

    const cursor = getCursorForEdge(tileResizing.edge)

    document.body.style.cursor = cursor
    document.body.style.userSelect = 'none'
    window.addEventListener('mousemove', handleTileResizeMove)
    window.addEventListener('mouseup', handleTileResizeUp)

    return () => {
      if (rafId !== null) cancelAnimationFrame(rafId)
      window.removeEventListener('mousemove', handleTileResizeMove)
      window.removeEventListener('mouseup', handleTileResizeUp)
    }
  }, [tileResizing, containerRef, effectiveLayoutRef, onLayoutChangeRef, setTileResizing, clientToCanvasPercentRef])
}

import { useState, useEffect, useCallback, useRef, MutableRefObject } from 'react'
import type { ClientToCanvasPercent } from './types.js'

interface UsePanningResult {
  panX: number
  isPanning: boolean
  handlePanStart: (e: React.MouseEvent) => void
  clientToCanvasPercent: ClientToCanvasPercent
  clientToCanvasPercentRef: MutableRefObject<ClientToCanvasPercent>
}

const DRAG_THRESHOLD = 3 // px of movement before we consider it a drag, not a click

export function usePanning(
  containerRef: MutableRefObject<HTMLDivElement | null>,
  canvasWidth: number,
  viewportWidth: number,
  viewportHeight: number
): UsePanningResult {
  const [panX, setPanX] = useState(0)
  const [isPanning, setIsPanning] = useState(false)
  const panXRef = useRef(panX)
  panXRef.current = panX

  const maxPan = Math.max(0, canvasWidth - viewportWidth)
  const maxPanRef = useRef(maxPan)
  maxPanRef.current = maxPan

  // Clamp panX when bounds change (e.g. tiles removed)
  useEffect(() => {
    if (panX > maxPan) {
      setPanX(maxPan)
    }
  }, [panX, maxPan])

  const clientToCanvasPercent: ClientToCanvasPercent = useCallback((clientX: number, clientY: number) => {
    const container = containerRef.current
    if (!container || viewportWidth === 0 || viewportHeight === 0) {
      return { x: 0, y: 0 }
    }
    const rect = container.getBoundingClientRect()
    const x = (clientX - rect.left + panXRef.current) / viewportWidth * 100
    const y = (clientY - rect.top) / viewportHeight * 100
    return { x, y }
  }, [containerRef, viewportWidth, viewportHeight])

  const clientToCanvasPercentRef = useRef(clientToCanvasPercent)
  clientToCanvasPercentRef.current = clientToCanvasPercent

  const handlePanStart = useCallback((e: React.MouseEvent) => {
    // Middle mouse button only
    if (e.button !== 1) return

    const startX = e.clientX
    const startY = e.clientY
    const startPanX = panXRef.current
    let dragging = false
    let rafId: number | null = null

    const handleMove = (moveE: MouseEvent) => {
      const dx = Math.abs(moveE.clientX - startX)
      const dy = Math.abs(moveE.clientY - startY)

      // Start panning once movement exceeds threshold
      if (!dragging && (dx > DRAG_THRESHOLD || dy > DRAG_THRESHOLD)) {
        dragging = true
        setIsPanning(true)
      }

      if (!dragging) return

      if (rafId !== null) return
      rafId = requestAnimationFrame(() => {
        rafId = null
        const panDx = startX - moveE.clientX
        const newPanX = Math.max(0, Math.min(maxPanRef.current, startPanX + panDx))
        setPanX(newPanX)
      })
    }

    // Suppress middle-click paste when we're dragging (not clicking)
    const suppressPaste = (pasteE: MouseEvent) => {
      if (dragging && pasteE.button === 1) {
        pasteE.preventDefault()
        pasteE.stopPropagation()
      }
    }

    const handleUp = (upE: MouseEvent) => {
      if (rafId !== null) cancelAnimationFrame(rafId)

      if (dragging) {
        // We were panning — suppress paste and clean up
        setIsPanning(false)
        upE.preventDefault()
        upE.stopPropagation()
        // Trigger terminal refit after panning
        window.dispatchEvent(new Event('resize'))
      }
      // If not dragging, do nothing — let xterm handle paste naturally

      window.removeEventListener('mousemove', handleMove)
      window.removeEventListener('mouseup', handleUp, true)
      // Defer removal: auxclick fires AFTER mouseup in the same cycle,
      // so the suppressPaste listener must survive until then
      setTimeout(() => {
        window.removeEventListener('click', suppressPaste, true)
        window.removeEventListener('auxclick', suppressPaste, true)
      }, 0)
    }

    window.addEventListener('mousemove', handleMove)
    window.addEventListener('mouseup', handleUp, true)      // capture phase
    window.addEventListener('click', suppressPaste, true)    // capture phase
    window.addEventListener('auxclick', suppressPaste, true) // capture phase — middle-click fires auxclick
  }, [])

  return {
    panX,
    isPanning,
    handlePanStart,
    clientToCanvasPercent,
    clientToCanvasPercentRef
  }
}

import { useMemo, useEffect, useRef, MutableRefObject } from 'react'
import type { TileLayout } from '../tiled-layout-utils.js'
import {
  generateDefaultLayout,
  validateLayout,
  addTileToLayout,
  removeTabFromTile,
  getAllTabIdsFromLayout,
  migrateTile
} from '../tiled-layout-utils.js'
import type { OpenTab } from './types.js'

export function useEffectiveLayout(
  layout: TileLayout[],
  tabs: OpenTab[],
  containerSizeRef: MutableRefObject<{ width: number; height: number }>,
  onLayoutChange: (layout: TileLayout[]) => void
): {
  effectiveLayout: TileLayout[]
  effectiveLayoutRef: MutableRefObject<TileLayout[]>
  activeTabIdRef: MutableRefObject<string | null>
} {
  const effectiveLayoutRef = useRef<TileLayout[]>([])
  const activeTabIdRef = useRef<string | null>(tabs.length > 0 ? tabs[tabs.length - 1].id : null)

  const effectiveLayout = useMemo(() => {
    const { width, height } = containerSizeRef.current

    if (layout.length === 0) {
      return generateDefaultLayout(tabs, width, height)
    }

    // Ensure all tiles are migrated to the new format
    const migratedLayout = layout.map(migrateTile)

    const layoutTabIds = getAllTabIdsFromLayout(migratedLayout)
    const tabIds = new Set(tabs.map(t => t.id))
    const addedTabs = tabs.filter(t => !layoutTabIds.has(t.id))
    const removedTabIds = [...layoutTabIds].filter(id => !tabIds.has(id))

    if (addedTabs.length === 0 && removedTabIds.length === 0) {
      return validateLayout(migratedLayout, tabs, width, height)
    }

    let newLayout = [...migratedLayout]

    // Remove tabs that no longer exist
    for (const removedId of removedTabIds) {
      newLayout = removeTabFromTile(newLayout, removedId, tabs, width, height)
    }

    // Add new tabs - each gets its own tile (no auto-grouping by project)
    for (const addedTab of addedTabs) {
      const existingIds = newLayout.map(l => l.id)
      const activeId = existingIds.length > 0 ? existingIds[existingIds.length - 1] : null
      newLayout = addTileToLayout(newLayout, addedTab.id, activeId, width, height)
    }

    if (tabs.length > 0) {
      activeTabIdRef.current = tabs[tabs.length - 1].id
    }

    return validateLayout(newLayout, tabs, width, height)
  }, [layout, tabs, containerSizeRef])

  effectiveLayoutRef.current = effectiveLayout

  useEffect(() => {
    const layoutTabIds = getAllTabIdsFromLayout(layout.map(migrateTile))
    const effectiveTabIds = getAllTabIdsFromLayout(effectiveLayout)
    const idsMatch = layoutTabIds.size === effectiveTabIds.size &&
      [...layoutTabIds].every(id => effectiveTabIds.has(id))

    if (!idsMatch) {
      onLayoutChange(effectiveLayout)
    }
  }, [effectiveLayout, layout, onLayoutChange])

  return { effectiveLayout, effectiveLayoutRef, activeTabIdRef }
}

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react'
import type { TileLayout, DropZone } from '../tiled-layout-utils.js'
import type { TiledTerminalViewProps, TileResizeState } from './types.js'
import { useEffectiveLayout } from './useEffectiveLayout.js'
import { useStartTileResize, useTileResizeEffect } from './useTileResizing.js'
import {
  useHandleDragStart,
  useHandleContainerDragOver,
  useHandleContainerDragLeave,
  useApplyDropZone,
  useHandleContainerDrop,
  useHandleDragEnd
} from './useTileDragDrop.js'
import { useGetHighlightedEdges, useHighlightedEdges } from './useHighlightedEdges.js'
import { usePanning } from './usePanning.js'
import { TileTerminal } from './TileTerminal.js'
import { DropZoneOverlay } from './DropZoneOverlay.js'

export type { TileLayout, DropZone } from '../tiled-layout-utils.js'
export { splitTile, addTileToLayout, addTabToExistingTile } from '../tiled-layout-utils.js'

const GAP = 4

export function TiledTerminalView({
  tabs,
  projects,
  theme,
  focusedTabId,
  onCloseTab,
  onFocusTab,
  layout,
  onLayoutChange,
  onOpenSessionAtPosition,
  onAddTab,
  onUndoCloseTab,
  api
}: TiledTerminalViewProps): React.ReactElement | null {
  const containerRef = useRef<HTMLDivElement>(null)
  const containerSizeRef = useRef({ width: 1920, height: 1080 })
  const [viewportSize, setViewportSize] = useState({ width: 1920, height: 1080 })
  const onLayoutChangeRef = useRef(onLayoutChange)
  onLayoutChangeRef.current = onLayoutChange

  useEffect(() => {
    const container = containerRef.current
    if (!container) return

    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect
        if (width > 0 && height > 0) {
          containerSizeRef.current = { width, height }
          setViewportSize({ width, height })
        }
      }
    })

    resizeObserver.observe(container)
    const rect = container.getBoundingClientRect()
    if (rect.width > 0 && rect.height > 0) {
      containerSizeRef.current = { width: rect.width, height: rect.height }
      setViewportSize({ width: rect.width, height: rect.height })
    }

    return () => resizeObserver.disconnect()
  }, [])

  const [draggedTile, setDraggedTile] = useState<string | null>(null)
  const [draggedSidebarProject, setDraggedSidebarProject] = useState<string | null>(null)
  const [dropTarget, setDropTarget] = useState<string | null>(null)
  const [currentDropZone, setCurrentDropZone] = useState<DropZone | null>(null)
  const [tileResizing, setTileResizing] = useState<TileResizeState | null>(null)
  const [hoveredEdge, setHoveredEdge] = useState<{ tileId: string; edge: string } | null>(null)

  const { effectiveLayout, effectiveLayoutRef } = useEffectiveLayout(
    layout, tabs, containerSizeRef, onLayoutChange
  )

  // Compute canvas width from tile positions, with padding so the rightmost edge is accessible
  const CANVAS_PADDING = 180 // px of extra space past the rightmost tile for resize handles
  const canvasWidth = useMemo(() => {
    if (effectiveLayout.length === 0) return viewportSize.width
    const rightmostEdge = Math.max(...effectiveLayout.map(t => t.x + t.width))
    const rightmostPx = rightmostEdge / 100 * viewportSize.width
    if (rightmostPx <= viewportSize.width) return viewportSize.width
    return rightmostPx + CANVAS_PADDING
  }, [effectiveLayout, viewportSize.width])

  const { panX, isPanning, handlePanStart, clientToCanvasPercent, clientToCanvasPercentRef } = usePanning(
    containerRef, canvasWidth, viewportSize.width, viewportSize.height
  )

  // Whether tiles extend beyond the viewport
  const hasOffscreenLeft = panX > 0
  const hasOffscreenRight = canvasWidth > viewportSize.width && panX < canvasWidth - viewportSize.width

  // Ctrl+Shift+T to undo close tab
  useEffect(() => {
    if (!onUndoCloseTab) return
    const handler = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'T') {
        e.preventDefault()
        onUndoCloseTab()
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [onUndoCloseTab])

  // Force terminals to refit when tiled view mounts
  useEffect(() => {
    const triggerRefit = () => {
      window.dispatchEvent(new Event('resize'))
    }
    const timers = [
      setTimeout(triggerRefit, 100),
      setTimeout(triggerRefit, 300),
    ]
    return () => timers.forEach(clearTimeout)
  }, [])

  const handleSwitchSubTab = useCallback((tileId: string, tabId: string) => {
    const newLayout = effectiveLayoutRef.current.map(tile => {
      if (tile.id === tileId) {
        return { ...tile, activeTabId: tabId }
      }
      return tile
    })
    onLayoutChange(newLayout)
  }, [effectiveLayoutRef, onLayoutChange])

  const startTileResize = useStartTileResize(effectiveLayout, setTileResizing, setHoveredEdge)
  useTileResizeEffect(tileResizing, containerRef, effectiveLayoutRef, onLayoutChangeRef, setTileResizing, clientToCanvasPercentRef)

  const dragDropActions = {
    setDraggedTile,
    setDraggedSidebarProject,
    setDropTarget,
    setCurrentDropZone
  }

  const handleDragStart = useHandleDragStart(setDraggedTile)
  const handleContainerDragOver = useHandleContainerDragOver(
    containerRef, effectiveLayout,
    { draggedTile, draggedSidebarProject },
    dragDropActions,
    clientToCanvasPercentRef
  )
  const handleContainerDragLeave = useHandleContainerDragLeave(containerRef, dragDropActions)
  const applyDropZone = useApplyDropZone(tabs, containerSizeRef)
  const handleContainerDrop = useHandleContainerDrop(
    containerRef, effectiveLayoutRef, containerSizeRef,
    tabs, onLayoutChange, applyDropZone, onOpenSessionAtPosition,
    dragDropActions,
    clientToCanvasPercentRef
  )
  const handleDragEnd = useHandleDragEnd(dragDropActions)

  const getHighlightedEdges = useGetHighlightedEdges(effectiveLayout)
  const highlightedEdges = useHighlightedEdges(hoveredEdge, tileResizing, getHighlightedEdges)

  if (tabs.length === 0) return null

  return (
    <div
      ref={containerRef}
      className={`terminal-tiled-custom${tileResizing ? ' is-resizing' : ''}${isPanning ? ' is-panning' : ''}`}
      style={{ flex: 1, padding: `${GAP}px`, overflow: 'hidden', background: 'var(--bg-base)', position: 'relative' }}
      onDragOver={handleContainerDragOver}
      onDragLeave={handleContainerDragLeave}
      onDrop={handleContainerDrop}
      onMouseDown={handlePanStart}
    >
      {tileResizing && (
        <div style={{ position: 'absolute', inset: 0, zIndex: 200, cursor: 'inherit' }} />
      )}

      <div
        className="tile-canvas"
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: `${canvasWidth}px`,
          height: '100%',
          transform: `translate(${-panX}px, 0)`
        }}
      >
        {effectiveLayout.map((tile) => {
          const tileTabs = tile.tabIds
            .map(id => tabs.find(t => t.id === id))
            .filter((t): t is typeof tabs[number] => t != null)

          if (tileTabs.length === 0) return null

          const activeSubTabId = tile.activeTabId && tileTabs.some(t => t.id === tile.activeTabId)
            ? tile.activeTabId
            : tileTabs[0].id

          const project = projects.find(p => p.path === tileTabs[0].projectPath)
          const isFocused = focusedTabId != null && tile.tabIds.includes(focusedTabId)

          return (
            <TileTerminal
              key={tile.id}
              tile={tile}
              tabs={tileTabs}
              activeSubTabId={activeSubTabId}
              project={project}
              theme={theme}
              api={api}
              GAP={GAP}
              isFocused={isFocused}
              isDragging={draggedTile === tile.id}
              isDropTarget={dropTarget === tile.id}
              draggedTile={draggedTile}
              draggedSidebarProject={draggedSidebarProject}
              effectiveLayout={effectiveLayout}
              containerRef={containerRef}
              highlightedEdges={highlightedEdges}
              viewportSize={viewportSize}
              clientToCanvasPercent={clientToCanvasPercent}
              onCloseTab={onCloseTab}
              onFocusTab={onFocusTab}
              onSwitchSubTab={handleSwitchSubTab}
              onAddTab={onAddTab}
              onDragStart={handleDragStart}
              onDragEnd={handleDragEnd}
              onContainerDrop={handleContainerDrop}
              startTileResize={startTileResize}
              setHoveredEdge={setHoveredEdge}
              setDraggedSidebarProject={setDraggedSidebarProject}
              setCurrentDropZone={setCurrentDropZone}
              setDropTarget={setDropTarget}
            />
          )
        })}

        {(draggedTile || draggedSidebarProject) && currentDropZone && (() => {
          // Compute contextual swap label based on whether this would merge or swap
          let swapLabel: string | undefined
          if (currentDropZone.type === 'swap') {
            if (draggedSidebarProject) {
              swapLabel = 'Add as Tab'
            } else if (draggedTile) {
              const sourceTile = effectiveLayout.find(t => t.id === draggedTile)
              const targetTile = effectiveLayout.find(t => t.id === currentDropZone.targetTileId)
              if (sourceTile && targetTile) {
                const sourceProject = sourceTile.tabIds
                  .map(id => tabs.find(t => t.id === id)?.projectPath)
                  .find(p => p != null)
                const targetProject = targetTile.tabIds
                  .map(id => tabs.find(t => t.id === id)?.projectPath)
                  .find(p => p != null)
                swapLabel = sourceProject && sourceProject === targetProject ? 'Add as Tab' : 'Swap'
              }
            }
          }
          return (
            <DropZoneOverlay
              currentDropZone={currentDropZone}
              draggedSidebarProject={draggedSidebarProject}
              swapLabel={swapLabel}
              GAP={GAP}
              viewportSize={viewportSize}
            />
          )
        })()}
      </div>

      {hasOffscreenLeft && <div className="pan-indicator-left" />}
      {hasOffscreenRight && <div className="pan-indicator-right" />}

      {onUndoCloseTab && (
        <button
          className="tile-undo-close"
          onClick={onUndoCloseTab}
          title="Reopen closed tab (Ctrl+Shift+T)"
        >
          Undo close
        </button>
      )}
    </div>
  )
}

export default TiledTerminalView

